def composite_logo(image_url, logo_url, fal_key):
    """Download image + logo, paste logo at left-chest position, upload result to FAL."""
    try:
        from PIL import Image
        import base64 as b64mod
        from io import BytesIO

        # Download base image
        img_resp = requests.get(image_url, timeout=20)
        img = Image.open(BytesIO(img_resp.content)).convert('RGBA')
        iw, ih = img.size

        # Download logo (should be transparent PNG from birefnet)
        logo_resp = requests.get(logo_url, timeout=20)
        logo = Image.open(BytesIO(logo_resp.content)).convert('RGBA')

        # Resize logo to ~12% of image width, keeping aspect ratio
        logo_w = int(iw * 0.12)
        ratio = logo_w / logo.width
        logo_h = int(logo.height * ratio)
        logo = logo.resize((logo_w, logo_h), Image.LANCZOS)

        # Tint logo white if image is dark at chest area
        # Sample brightness at left-chest area (20% from left, 35% from top)
        cx, cy = int(iw * 0.20), int(ih * 0.35)
        sample = img.crop((cx-20, cy-20, cx+20, cy+20)).convert('RGB')
        pixels = list(sample.getdata())
        avg_brightness = sum(r+g+b for r,g,b in pixels) / (len(pixels) * 3)

        if avg_brightness < 128:
            # Dark background — make logo white
            r_ch, g_ch, b_ch, a_ch = logo.split()
            white_logo = Image.merge('RGBA', [
                Image.new('L', logo.size, 255),
                Image.new('L', logo.size, 255),
                Image.new('L', logo.size, 255),
                a_ch
            ])
            logo = white_logo

        # Position: left chest — 8% from left, 30% from top
        paste_x = int(iw * 0.08)
        paste_y = int(ih * 0.30)

        # Paste with transparency mask
        img.paste(logo, (paste_x, paste_y), logo)

        # Convert back to RGB and save as JPEG
        final = img.convert('RGB')
        buf = BytesIO()
        final.save(buf, format='JPEG', quality=92)
        buf.seek(0)
        img_bytes = buf.read()

        # Upload to FAL storage
        fal_headers = {'Authorization': f'Key {fal_key}', 'Content-Type': 'application/json'}
        import time as _time
        key = f'logo_comp_{int(_time.time()*1000)}.jpg'
        init_resp = requests.post(
            'https://rest.alpha.fal.ai/storage/upload/initiate',
            headers=fal_headers,
            json={'file_name': key, 'content_type': 'image/jpeg'},
            timeout=15
        )
        init_resp.raise_for_status()
        init_data = init_resp.json()
        requests.put(init_data['upload_url'], data=img_bytes, headers={'Content-Type': 'image/jpeg'}, timeout=30)
        return init_data['file_url']

    except Exception as e:
        print(f'Logo composite error: {e}')
        return image_url  # fallback to original


@app.route('/api/generate', methods=['POST'])
def generate():
    try:
        data = request.json
        mood = data.get('mood', '')
        image_url = data.get('image_url', '')
        skip_composite = data.get('skip_composite', False)

        # Pick 3 different fabric phrases randomly
        phrases = random.sample(FABRIC_PHRASES, 3)
        prompt = (WEARTH_PROMPT
            .replace('MOOD_PLACEHOLDER', mood)
            .replace('FABRIC_A', phrases[0])
            .replace('FABRIC_B', phrases[1])
            .replace('FABRIC_C', phrases[2])
        )

        claude_resp = requests.post(
            'https://api.anthropic.com/v1/messages',
            headers={'Content-Type': 'application/json', 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01'},
            json={'model': 'claude-sonnet-4-20250514', 'max_tokens': 2000, 'messages': [{'role': 'user', 'content': prompt}]},
            timeout=40
        )
        claude_data = claude_resp.json()
        raw_text = claude_data['content'][0]['text'].strip()
        if '```' in raw_text:
            parts = raw_text.split('```')
            raw_text = parts[1] if len(parts) > 1 else parts[0]
            if raw_text.startswith('json'):
                raw_text = raw_text[4:]
            raw_text = raw_text.strip()

        parsed = json.loads(raw_text)
        headline = parsed.get('headline', 'move with intention.')
        tagline = parsed.get('tagline', 'plant-based · wearth')
        captions = parsed.get('captions', [parsed.get('caption', '')])
        if not isinstance(captions, list):
            captions = [captions]

        logo_url = data.get('logo_url', '')

        if skip_composite:
            stable_url = image_url
        else:
            comp_resp = requests.post(
                COMPOSITOR_URL,
                json={'photo_url': image_url, 'main_text': headline, 'sub_text': tagline, 'logo_base64': ''},
                timeout=60
            )
            comp_data = comp_resp.json()
            stable_url = comp_data.get('url', image_url)

        # Apply logo overlay if selected (works for both composite and skip_composite)
        if logo_url:
            stable_url = composite_logo(stable_url, logo_url, FAL_API_KEY)

        return jsonify({'image_url': stable_url, 'headline': headline, 'tagline': tagline, 'captions': captions})

    except Exception as e:
        return jsonify({'error': str(e), 'trace': traceback.format_exc()}), 500


@app.route('/api/rephrase', methods=['POST'])
def rephrase():
    """Take Shai's raw draft and rephrase it in WEARTH voice."""
    try:
        data = request.json
        draft = data.get('draft', '').strip()
        if not draft:
            return jsonify({'error': 'draft required'}), 400

        prompt = REPHRASE_PROMPT.replace('DRAFT_PLACEHOLDER', draft)

        claude_resp = requests.post(
            'https://api.anthropic.com/v1/messages',
            headers={'Content-Type': 'application/json', 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01'},
            json={'model': 'claude-sonnet-4-20250514', 'max_tokens': 600, 'messages': [{'role': 'user', 'content': prompt}]},
            timeout=30
        )
        result = claude_resp.json()['content'][0]['text'].strip()
        return jsonify({'rephrased': result})

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/upload-image', methods=['POST'])
def upload_image():
    """Upload an image via FAL storage and return a public URL."""
    try:
        fal_headers = {'Authorization': f'Key {FAL_API_KEY}', 'Content-Type': 'application/json'}

        # Get base64 image data from request
        data = request.json
        image_b64 = data.get('image_b64', '')
        content_type = data.get('content_type', 'image/jpeg')
        ext = content_type.split('/')[-1]

        if not image_b64:
            return jsonify({'error': 'image_b64 required'}), 400

        import base64 as b64mod
        img_bytes = b64mod.b64decode(image_b64)

        # Initiate FAL storage upload
        init_resp = requests.post(
            'https://rest.alpha.fal.ai/storage/upload/initiate',
            headers=fal_headers,
            json={'file_name': f'upload.{ext}', 'content_type': content_type},
            timeout=15
        )
        init_resp.raise_for_status()
        init_data = init_resp.json()
        upload_url = init_data.get('upload_url', '')
        file_url = init_data.get('file_url', '')

        if not upload_url:
            return jsonify({'error': 'No upload_url from FAL', 'raw': init_data}), 500

        # Upload the bytes
        put_resp = requests.put(
            upload_url,
            data=img_bytes,
            headers={'Content-Type': content_type},
            timeout=30
        )
        put_resp.raise_for_status()

        return jsonify({'url': file_url})

    except Exception as e:
        return jsonify({'error': str(e), 'trace': traceback.format_exc()}), 500


